import java.util.ArrayList;
import java.util.List;

public class Main {
    static List<Integer> heap = new ArrayList<>();

    static void insert(int value) {
        heap.add(value); // add at the end
        siftUp(heap.size() - 1);
    }

    static void siftUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap.get(index) < heap.get(parent)) {
                int temp = heap.get(index);
                heap.set(index, heap.get(parent));
                heap.set(parent, temp);
                index = parent;
            } else {
                break;
            }
        }
    }

    public static void main(String[] args) {
        insert(10);
        insert(5);
        insert(15);
        insert(2);

        System.out.println(heap);
    }
}

import java.util.ArrayList;
import java.util.List;

public class Main {
    static List<Integer> heap = new ArrayList<>();

    static void insert(int value) {
        heap.add(value);
        siftUp(heap.size() - 1);
    }

    static void siftUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap.get(index) < heap.get(parent)) {
                swap(index, parent);
                index = parent;
            } else {
                break;
            }
        }
    }

    static int extractMin() {
        int min = heap.get(0);
        int last = heap.remove(heap.size() - 1);

        if (!heap.isEmpty()) {
            heap.set(0, last);
            siftDown(0);
        }
        return min;
    }

    static void siftDown(int index) {
        int size = heap.size();
        while (true) {
            int left = 2 * index + 1;
            int right = 2 * index + 2;
            int smallest = index;

            if (left < size && heap.get(left) < heap.get(smallest)) {
                smallest = left;
            }
            if (right < size && heap.get(right) < heap.get(smallest)) {
                smallest = right;
            }
            if (smallest == index) {
                break;
            }
            swap(index, smallest);
            index = smallest;
        }
    }

    static void swap(int i, int j) {
        int temp = heap.get(i);
        heap.set(i, heap.get(j));
        heap.set(j, temp);
    }

    public static void main(String[] args) {
        insert(5);
        insert(10);
        insert(15);
        insert(2);

        System.out.println(extractMin());
        System.out.println(heap);
    }
}

